mapper.select:
SELECT p.prodNo, p.prodName, p.price, p.discount, p.point, p.sold, COALESCE(SUM(pv.stock), 0) AS stock, p.thumb1FileId, p.sellerUid FROM product p LEFT JOIN product_variant pv ON pv.prodNo = p.prodNo
p.sellerUid = #{seller}
AND CAST(p.prodNo AS CHAR) LIKE CONCAT('%', #{keyword}, '%')
AND p.prodName LIKE CONCAT('%', #{keyword}, '%')
AND EXISTS ( SELECT 1 FROM member m WHERE m.uid = p.sellerUid AND m.name LIKE CONCAT('%', #{keyword}, '%') )
GROUP BY p.prodNo, p.prodName, p.price, p.discount, p.point, p.sold, p.thumb1FileId, p.sellerUid ORDER BY p.prodNo DESC LIMIT #{size} OFFSET #{offset}
